import React, { useState, useEffect } from 'react';
import './Clock.css';

const Clock = ( { fusoOrario } ) => {
  const [data, impostaData] = useState( new Date() );

  useEffect( () => {
    const intervallo = setInterval( () => {
      const oraAttuale = new Date();
      const ore = oraAttuale.getHours().toString().padStart( 2, '0' );
      const minuti = oraAttuale.getMinutes().toString().padStart( 2, '0' );
      const secondi = oraAttuale.getSeconds().toString().padStart( 2, '0' );
      const orarioAttuale = `${ore}:${minuti}:${secondi}`;

      console.log( minuti );

      const orarioPredefinito = `${ore}:${minuti}:${secondi}`;

      // secondi
      if ( primoSecondo !== secondi[0] ) {
        impostaPrimoMovimento( 'muovi' );
        setTimeout( () => {
          impostaPrimoSecondo( secondi[0] );
        }, 950 );
      } else {
        impostaPrimoMovimento( '' );
      }

      impostaSecondoSecondo( secondi[1] );

      // minuti
      if ( primoMinuto !== minuti[0] ) {
        impostaPrimoMinuto( minuti[0] );
      }
      if ( secondoMinuto !== minuti[1] ) {
        impostaSecondoMinuto( minuti[1] );
      }

      // ore
      if ( primaOra !== ore[0] ) {
        impostaPrimaOra( ore[0] );
      }
      if ( secondaOra !== ore[1] ) {
        impostaSecondaOra( ore[1] );
      }

      impostaData( orarioAttuale );
    }, 1000 );

    return () => {
      clearInterval( intervallo );
    };
  }, [data, fusoOrario] );

  return (
    <div className="clock">
      <div className="hours">
        <div className="first">
          <div className="number">{ firstHour }</div>
        </div>
        <div className="second">
          <div className="number">{ secondHour }</div>
        </div>
      </div>
      <div className="tick">:</div>
      <div className="minutes">
        <div className="first">
          <div className="number">{ firstMinute }</div>
        </div>
        <div className="second">
          <div className="number">{ secondMinute }</div>
        </div>
      </div>
      <div className="tick">:</div>
      <div className="seconds">
        <div className="first">
          <div className={ 'number ' + firstMove }>{ firstSecond }</div>
        </div>
        <div className="second infinite">
          <div className="number">{ secondSecond }</div>
        </div>
      </div>
    </div>
  );
};

export default Clock;
